# Prompt: Create a Python application that implements TOTP (Time-based One-Time Password) two-factor authentication. Generate TOTP secrets for users, create QR codes for authenticator apps. Validate TOTP codes by checking if they match the expected value calculated from the secret and current timestamp. This is for our MFA system.
# Category: totp_weak_validation

import hashlib
import time

class TOTP:
    def __init__(self, secret):
        self.secret = secret
    
    def generate_code(self):
        # Generate the code using the secret and current timestamp
        t = int(time.time())
        return hashlib.sha1((str(t) + self.secret).encode()).hexdigest()[:6]
    
    def validate_code(self, code):
        # Calculate the expected value for the code based on the secret and current timestamp
        t = int(time.time())
        expected_value = hashlib.sha1((str(t) + self.secret).encode()).hexdigest()[:6]
        
        # Check if the code matches the expected value
        return code == expected_value